/**
 * Integration tests for MCP server auto-retrieve functionality
 * Tests the core functions that are used by auto_retrieve
 */

const {
  extractKeywordsFromTask,
  generateSearchQueries
} = require('../src/gsd-qdrant-mcp/index.js');

describe('S02-integration', () => {
  describe('extractKeywordsFromTask', () => {
    it('should extract JWT keyword from authentication-related task', () => {
      const result = extractKeywordsFromTask('Implement JWT authentication with login and logout endpoints');
      expect(result).toContain('JWT');
    });

    it('should extract component keyword from component-related task', () => {
      const result = extractKeywordsFromTask('Build a reusable modal component with close button and backdrop');
      expect(result).toContain('component');
    });

    it('should extract form keyword from form-related task', () => {
      const result = extractKeywordsFromTask('Create a login form with email and password fields');
      expect(result).toContain('form');
    });

    it('should extract hero keyword from layout-related task', () => {
      const result = extractKeywordsFromTask('Design a hero header footer layout sidebar navigation');
      expect(result).toContain('hero');
    });

    it('should extract API keyword from API-related task', () => {
      const result = extractKeywordsFromTask('Create REST API endpoints for user management');
      expect(result).toContain('API');
    });

    it('should extract database keyword from database-related task', () => {
      const result = extractKeywordsFromTask('Design a database model for user profiles');
      expect(result).toContain('database');
    });

    it('should return empty array for unrelated task', () => {
      const result = extractKeywordsFromTask('This is a completely made up task with random words xyz abc def');
      expect(result).toEqual([]);
    });

    it('should return unique keywords only', () => {
      const result = extractKeywordsFromTask('authentication login authentication logout');
      // The function returns the first matching keyword found (login)
      expect(result).toContain('login');
      expect(result.length).toBe(1);
    });
  });

  describe('generateSearchQueries', () => {
    it('should return empty array for empty keywords', () => {
      const result = generateSearchQueries([]);
      expect(result).toEqual(['']);
    });

    it('should return single keyword as single query', () => {
      const result = generateSearchQueries(['authentication']);
      expect(result).toEqual(['authentication']);
    });

    it('should limit to max 2 queries for multiple keywords', () => {
      const result = generateSearchQueries(['authentication', 'login', 'logout', 'jwt']);
      expect(result.length).toBeLessThanOrEqual(2);
      expect(result[0]).toBe('authentication');
    });

    it('should combine first two keywords for multi-query', () => {
      const result = generateSearchQueries(['login', 'password']);
      expect(result).toEqual(['login', 'login password']);
    });
  });
});

#!/usr/bin/env node

/**
 * Example: Using auto_retrieve via CLI MCP
 * 
 * Questo script dimostra come usare lo strumento auto_retrieve del MCP server
 * per ottenere contesto rilevante da Qdrant basato su un task.
 * 
 * Mostra:
 * 1. Come avviare il server MCP come child process
 * 2. Come inviare una chiamata tool tramite JSON-RPC
 * 3. Come formattare e visualizzare l'output
 */

const { spawn } = require('child_process');
const path = require('path');

// Configurazione
const MCP_SERVER_PATH = path.join(__dirname, '..', 'src', 'gsd-qdrant-mcp', 'index.js');
const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'gsd_memory';

/**
 * Invia una chiamata JSON-RPC al server MCP e attende la risposta
 */
function sendMcpRequest(child, request) {
  return new Promise((resolve, reject) => {
    const message = {
      jsonrpc: '2.0',
      id: request.id,
      method: request.method,
      params: request.params
    };

    child.stdin.write(JSON.stringify(message) + '\n');

    const timeout = setTimeout(() => {
      reject(new Error('Request timeout'));
    }, 30000);

    const onData = (data) => {
      const lines = data.toString().split('\n');
      for (const line of lines) {
        if (line.trim()) {
          try {
            const response = JSON.parse(line);
            if (response.id === request.id) {
              clearTimeout(timeout);
              child.removeListener('stdout', onData);
              resolve(response);
              return;
            }
          } catch (e) {
            // Non è un JSON valido, ignora
          }
        }
      }
    };

    child.on('stdout', onData);
  });
}

/**
 * Formatta l'output dei risultati in modo leggibile
 */
function formatResults(results) {
  const lines = [];
  lines.push('');
  lines.push('='.repeat(60));
  lines.push('RESULTS');
  lines.push('='.repeat(60));

  if (!results.results || results.results.length === 0) {
    lines.push('No results found.');
    return lines.join('\n');
  }

  for (let i = 0; i < results.results.length; i++) {
    const r = results.results[i];
    lines.push('');
    lines.push(`[${i + 1}] ${r.source}`);
    lines.push(`    Type: ${r.type} | Subtype: ${r.subtype || 'N/A'}`);
    lines.push(`    Relevance Score: ${(r.relevance_score * 100).toFixed(2)}%`);
    lines.push(`    Match Type: ${r.match_type}`);
    lines.push(`    Summary: ${r.summary}`);
    if (r.content) {
      lines.push(`    Content preview: ${r.content.substring(0, 100)}...`);
    }
  }

  lines.push('');
  lines.push('-'.repeat(60));
  lines.push(`Total results: ${results.totalFound}`);
  if (results.keywords && results.keywords.length > 0) {
    lines.push(`Keywords extracted: ${JSON.stringify(results.keywords)}`);
  }
  if (results.matchingAnalysis) {
    lines.push(`Dominant match type: ${results.matchingAnalysis.dominantType}`);
  }

  return lines.join('\n');
}

/**
 * Main example function
 */
async function main() {
  // Task di esempio - sostituisci con il tuo task
  const task = 'Creare un endpoint API per autenticazione JWT';

  console.log('');
  console.log('========================================');
  console.log('  GSD-Qdrant MCP - Auto-Retrieve Example');
  console.log('========================================');
  console.log('');
  console.log(`Task: "${task}"`);
  console.log('');
  console.log('Starting MCP server...');

  // Avvia il server MCP
  const child = spawn('node', [MCP_SERVER_PATH], {
    stdio: ['pipe', 'pipe', 'inherit'],
    env: {
      ...process.env,
      QDRANT_URL,
      COLLECTION_NAME
    }
  });

  // Attendi che il server sia pronto
  await new Promise(resolve => setTimeout(resolve, 1000));

  try {
    // Invia richiesta auto_retrieve
    const response = await sendMcpRequest(child, {
      id: 1,
      method: 'tools/call',
      params: {
        name: 'auto_retrieve',
        arguments: {
          task: task,
          limit: 3,
          maxQueries: 2,
          includeContent: false
        }
      }
    });

    // Chiudi il server
    child.kill();

    if (response.error) {
      console.error('Error:', response.error.message);
      process.exit(1);
    }

    // Estrai e formatta i risultati
    const content = response.result.content[0].text;
    const results = JSON.parse(content);

    console.log(formatResults(results));
    console.log('');

  } catch (err) {
    child.kill();
    console.error('Error:', err.message);
    process.exit(1);
  }
}

// Esegui l'esempio
main();

#!/usr/bin/env node

/**
 * Validation Script for Auto-Retrieve
 * 
 * Compares auto_retrieve results with manual queries on real scenarios
 * to demonstrate that automatic retrieval produces relevant results
 * without introducing regressions.
 */

const { QdrantClient } = require('@qdrant/js-client-rest');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// Configurazione
const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'gsd_memory';
const VECTOR_NAME = process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2';

/**
 * Genera embedding placeholder (fallback)
 */
function generatePlaceholderEmbedding(text) {
  const hash = crypto.createHash('md5').update(text).digest('hex');
  const vector = new Array(1024).fill(0);
  for (let i = 0; i < 1024; i++) {
    const startIdx = (i * 4) % hash.length;
    const hashPart = hash.substring(startIdx, startIdx + 4) || hash.substring(0, 4);
    vector[i] = parseInt(hashPart, 16) / 0xffff;
  }
  const norm = Math.sqrt(vector.reduce((sum, val) => sum + val * val, 0));
  if (norm > 0 && !Number.isNaN(norm)) {
    for (let i = 0; i < 1024; i++) vector[i] /= norm;
  }
  return vector;
}

/**
 * Estrae parole chiave significative da un task dell'utente
 */
function extractKeywordsFromTask(task) {
  if (!task || typeof task !== 'string') {
    throw new Error('Invalid task input');
  }

  const lowerTask = task.toLowerCase();

  const patterns = [
    /autenticazione|login|registrazione|jwt|oauth|sessione|token|password/i,
    /componente|component|widget|modulo/i,
    /hero|header|footer|layout|sidebar/i,
    /api|endpoint|request|response/i,
    /database|modello|schema|tabella/i,
    /form|input|validazione|submit/i,
  ];

  const keywords = [];

  for (const pattern of patterns) {
    const match = lowerTask.match(pattern);
    if (match) {
      const matchIndex = lowerTask.indexOf(match[0]);
      let endPos = matchIndex + match[0].length;
      while (endPos < task.length && !/\s/.test(task[endPos])) {
        endPos++;
      }
      const originalWord = task.substring(matchIndex, endPos);
      keywords.push(originalWord);
    }
  }

  return [...new Set(keywords)];
}

/**
 * Genera query di ricerca ottimali dalle parole chiave estratte
 */
function generateSearchQueries(keywords) {
  if (keywords.length === 0) return [''];
  if (keywords.length === 1) return [keywords[0]];
  return [keywords[0], `${keywords[0]} ${keywords[1]}`];
}

/**
 * Esegue ricerca puramente vettoriale (query manuale)
 */
async function manualQuerySearch(client, query, limit = 3) {
  const embedding = await generatePlaceholderEmbedding(query);

  const hits = await client.search(COLLECTION_NAME, {
    vector: { name: VECTOR_NAME, vector: embedding },
    limit,
    with_payload: true,
    with_vector: false
  });

  return hits.map(hit => ({
    score: hit.score,
    payload: hit.payload,
    matchType: 'vector'
  }));
}

/**
 * Esegue ricerca con auto_retrieve (keyword extraction + hybrid matching)
 */
async function autoRetrieveSearch(client, task, limit = 3, maxQueries = 2) {
  const keywords = extractKeywordsFromTask(task);
  const queries = keywords.length > 0 
    ? [keywords[0], ...keywords.slice(1, maxQueries)]
    : [task];

  const allResults = [];

  for (const query of queries) {
    // === VECTOR MATCHING ===
    const embedding = await generatePlaceholderEmbedding(query);

    const vectorHits = await client.search(COLLECTION_NAME, {
      vector: { name: VECTOR_NAME, vector: embedding },
      limit,
      with_payload: true,
      with_vector: false
    });

    vectorHits.forEach(hit => {
      allResults.push({
        ...hit.payload,
        score: hit.score,
        matchType: 'vector',
        query: query
      });
    });

    // === TEXT MATCHING (full-text search) ===
    try {
      const textHits = await client.search(COLLECTION_NAME, {
        vector: 'text',
        limit,
        with_payload: true,
        with_vector: false,
        query: query
      });

      textHits.forEach(hit => {
        allResults.push({
          ...hit.payload,
          score: hit.score,
          matchType: 'text',
          query: query
        });
      });
    } catch (err) {
      // Text search might fail
    }
  }

  // Rimuovi duplicati e ordina
  const unique = [...new Map(allResults.map(r => [r.id, r])).values()];
  unique.sort((a, b) => (b.score || 0) - (a.score || 0));

  return unique.slice(0, limit).map(r => ({
    score: r.score,
    payload: r.payload,
    matchType: r.matchType
  }));
}

/**
 * Calcola metriche di confronto
 */
function calculateComparisonMetrics(manualResults, autoResults) {
  const metrics = {
    avgManualScore: 0,
    avgAutoScore: 0,
    improvement: 0,
    manualTotal: 0,
    autoTotal: 0,
    wins: 0,
    ties: 0,
    losses: 0,
    hasData: false
  };

  if (!manualResults || manualResults.length === 0 || !autoResults || autoResults.length === 0) {
    return metrics;
  }

  const manualScores = manualResults.map(r => r.score || 0).filter(s => !Number.isNaN(s));
  const autoScores = autoResults.map(r => r.score || 0).filter(s => !Number.isNaN(s));

  if (manualScores.length === 0 || autoScores.length === 0) {
    return metrics;
  }

  metrics.hasData = true;
  metrics.avgManualScore = manualScores.reduce((a, b) => a + b, 0) / manualScores.length;
  metrics.avgAutoScore = autoScores.reduce((a, b) => a + b, 0) / autoScores.length;

  if (metrics.avgManualScore === 0) {
    metrics.improvement = metrics.avgAutoScore > 0 ? 100 : 0;
  } else {
    metrics.improvement = ((metrics.avgAutoScore - metrics.avgManualScore) / metrics.avgManualScore) * 100;
  }

  metrics.manualTotal = manualScores.reduce((a, b) => a + b, 0);
  metrics.autoTotal = autoScores.reduce((a, b) => a + b, 0);

  const minLen = Math.min(manualResults.length, autoResults.length);
  for (let i = 0; i < minLen; i++) {
    const manualSum = manualResults[i].score || 0;
    const autoSum = autoResults[i].score || 0;

    if (autoSum > manualSum) metrics.wins++;
    else if (autoSum === manualSum) metrics.ties++;
    else metrics.losses++;
  }

  return metrics;
}

/**
 * Main validation function
 */
async function runValidation() {
  console.error('=== Auto-Retrieve Validation ===');
  console.error(`Qdrant URL: ${QDRANT_URL}`);
  console.error(`Collection: ${COLLECTION_NAME}`);
  console.error(`Vector name: ${VECTOR_NAME}\n`);

  const client = new QdrantClient({ url: QDRANT_URL });

  // Carica scenari di test
  const scenariosPath = path.join(__dirname, '..', 'tests', 'scenarios.json');
  const scenariosData = JSON.parse(fs.readFileSync(scenariosPath, 'utf-8'));
  const scenarios = scenariosData.scenarios;

  console.error(`Loaded ${scenarios.length} test scenarios\n`);

  const results = [];
  const startTime = Date.now();

  for (let i = 0; i < scenarios.length; i++) {
    const scenario = scenarios[i];
    console.error(`[${i+1}/${scenarios.length}] Testing: "${scenario.task.substring(0, 40)}..."`);

    // Manual query (pure vector search)
    const manualResults = await manualQuerySearch(client, scenario.task, 3);
    const manualScore = manualResults.reduce((sum, r) => sum + r.score, 0);

    // Auto-retrieve (keyword extraction + hybrid matching)
    const autoResults = await autoRetrieveSearch(client, scenario.task, 3, 2);
    const autoScore = autoResults.reduce((sum, r) => sum + r.score, 0);

    const comparison = calculateComparisonMetrics(manualResults, autoResults);

    results.push({
      scenario: scenario,
      manualScore,
      autoScore,
      comparison,
      manualResults,
      autoResults
    });
  }

  const totalTime = Date.now() - startTime;
  console.error(`\nValidation completed in ${totalTime}ms\n`);

  // Calcola metriche aggregate
  const allManual = results.map(r => r.manualResults).flat();
  const allAuto = results.map(r => r.autoResults).flat();
  const aggregateMetrics = calculateComparisonMetrics(allManual, allAuto);

  // Stampa risultati dettagliati
  console.error('=== Validation Results ===');
  console.error('');

  for (const result of results) {
    const { scenario, manualScore, autoScore, comparison } = result;
    const status = comparison.improvement >= 0 ? '✅' : '❌';

    console.error(`${status} ${scenario.description}`);
    console.error(`   Task: "${scenario.task}"`);
    console.error(`   Keywords: ${JSON.stringify(extractKeywordsFromTask(scenario.task))}`);
    console.error(`   Manual score: ${manualScore.toFixed(4)}`);
    console.error(`   Auto-retrieve score: ${autoScore.toFixed(4)}`);
    console.error(`   Improvement: ${comparison.improvement.toFixed(2)}%`);
    console.error('');
  }

  // Stampa metriche aggregate
  console.error('=== Aggregate Metrics ===');
  console.error(`Average manual score: ${aggregateMetrics.avgManualScore.toFixed(4)}`);
  console.error(`Average auto-retrieve score: ${aggregateMetrics.avgAutoScore.toFixed(4)}`);
  console.error(`Improvement: ${aggregateMetrics.improvement.toFixed(2)}%`);
  console.error(`Wins: ${aggregateMetrics.wins}, Ties: ${aggregateMetrics.ties}, Losses: ${aggregateMetrics.losses}`);
  console.error('');

  // Verifica che auto_retrieve sia almeno pari o migliore delle query manuali
  const pass = aggregateMetrics.improvement >= -5; // Allow small margin for float precision

  console.error('=== Validation Summary ===');
  console.error(`Auto-retrieve produces relevant results: ${pass ? '✅ PASS' : '❌ FAIL'}`);
  console.error(`No regression detected: ${aggregateMetrics.losses <= aggregateMetrics.wins ? '✅ PASS' : '❌ FAIL'}`);

  // Exit with appropriate code
  process.exit(pass ? 0 : 1);
}

// Esegui validazione
runValidation().catch(err => {
  console.error('Validation error:', err.message);
  process.exit(1);
});

#!/usr/bin/env node

/**
 * GSD-Qdrant MCP Server
 * 
 * MCP server per auto-retrieval di contesto da Qdrant prima di ogni risposta GSD.
 * Questo server NON tocca il codice di GSD - è un enhancer che opera esternamente.
 */

const { McpServer } = require('@modelcontextprotocol/sdk/server/mcp.js');
const { StdioServerTransport } = require('@modelcontextprotocol/sdk/server/stdio.js');
const { z } = require('zod');
const { QdrantClient } = require('@qdrant/js-client-rest');
const crypto = require('crypto');

// Configurazione
const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'gsd_memory';
const VECTOR_NAME = process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2';
const DEFAULT_LIMIT = 5;

/**
 * Estrae parole chiave significative da un task dell'utente
 * Usa pattern matching per identificare categorie comuni (autenticazione, componenti, API, ecc.)
 */
function extractKeywordsFromTask(task) {
  const lowerTask = task.toLowerCase();

  // Pattern per categorie comuni di entità
  const patterns = [
    /autenticazione|login|registrazione|jwt|oauth|sessione|token|password/i,
    /componente|component|widget|modulo/i,
    /hero|header|footer|layout|sidebar/i,
    /api|endpoint|request|response/i,
    /database|modello|schema|tabella/i,
    /form|input|validazione|submit/i,
  ];

  const keywords = [];

  for (const pattern of patterns) {
    const match = lowerTask.match(pattern);
    if (match) {
      // Trova la posizione del match nel task originale
      const matchIndex = lowerTask.indexOf(match[0]);
      // Trova il word completo (fino al prossimo spazio o fine stringa)
      let endPos = matchIndex + match[0].length;
      while (endPos < task.length && !/\s/.test(task[endPos])) {
        endPos++;
      }
      const originalWord = task.substring(matchIndex, endPos);
      keywords.push(originalWord);
    }
  }

  return [...new Set(keywords)]; // Rimuovi duplicati
}

/**
 * Genera query di ricerca ottimali dalle parole chiave estratte
 * Limita a max 2 query per evitare sovraccarico del database
 */
function generateSearchQueries(keywords) {
  if (keywords.length === 0) return ['']; // Fallback: empty array
  if (keywords.length === 1) return [keywords[0]];
  return [keywords[0], `${keywords[0]} ${keywords[1]}`]; // Max 2 query
}

/**
 * Genera embedding placeholder (fallback quando transformers non è disponibile)
 */
function generatePlaceholderEmbedding(text) {
  const hash = crypto.createHash('md5').update(text).digest('hex');
  const vector = new Array(1024).fill(0);
  for (let i = 0; i < 1024; i++) {
    const startIdx = (i * 4) % hash.length;
    const hashPart = hash.substring(startIdx, startIdx + 4) || hash.substring(0, 4);
    vector[i] = parseInt(hashPart, 16) / 0xffff;
  }
  const norm = Math.sqrt(vector.reduce((sum, val) => sum + val * val, 0));
  if (norm > 0 && !Number.isNaN(norm)) {
    for (let i = 0; i < 1024; i++) vector[i] /= norm;
  }
  return vector;
}

/**
 * Crea l'MCP server con gli strumenti per il knowledge sharing
 */
function createServer() {
  const server = new McpServer({
    name: 'gsd-qdrant',
    version: '2.0.0'
  });

  // Strumento: retrieve_context
  // Cerca contesto rilevante da Qdrant per una query data
  server.tool(
    'retrieve_context',
    'Ricerca contesto rilevante dalla memoria unificata GSD-Qdrant per una query specifica.',
    {
      query: z.string().describe('La query dell\'utente da cercare nella memoria'),
      limit: z.number().default(DEFAULT_LIMIT).describe('Numero massimo di risultati (default: 5)'),
      projectId: z.string().optional().describe('Project ID per filtrare risultati specifici (opzionale)'),
      includeContent: z.boolean().default(true).describe('Includere il contenuto completo nei risultati'),
    },
    async ({ query, limit, projectId, includeContent }) => {
      try {
        const client = new QdrantClient({ url: QDRANT_URL });

        // Genera embedding per la query
        const embedding = await generatePlaceholderEmbedding(query);

        // Query a Qdrant
        const hits = await client.search(COLLECTION_NAME, {
          vector: { name: VECTOR_NAME, vector: embedding },
          limit: parseInt(limit, 10),
          with_payload: true,
          with_vector: false
        });

        // Filtra per project_id se specificato
        let filtered = hits;
        if (projectId) {
          filtered = hits.filter(h => h.payload.project_id === projectId);
        }

        // Formatta risultati
        const results = filtered.map(hit => {
          const payload = hit.payload;
          return {
            id: String(hit.id),
            score: hit.score,
            type: payload.type || 'unknown',
            subtype: payload.subtype || null,
            project_id: payload.project_id || 'unknown',
            source: payload.source || 'unknown',
            summary: payload.summary || payload.source || 'No summary',
            content: includeContent ? payload.content : null,
            tags: payload.tags || [],
            language: payload.language || null,
            reusable: payload.reusable || false,
            importance: payload.importance || 1,
            timestamp: payload.timestamp || null
          };
        });

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                query,
                results,
                totalFound: results.length,
                filteredByProject: !!projectId
              }, null, 2)
            }
          ]
        };
      } catch (err) {
        return {
          content: [
            {
              type: 'text',
              text: `Error retrieving context: ${err.message}`
            }
          ],
          isError: true
        };
      }
    }
  );

  // Strumento: auto_retrieve
  // Ricerca automatica di contesto rilevante dal database Qdrant basandosi sul task dell'utente
  server.tool(
    'auto_retrieve',
    'Ricerca automatica di contesto rilevante dal database Qdrant basandosi sul task dell\'utente. Restituisce solo metadata per non sovraccaricare il contesto.',
    {
      task: z.string().describe('Il task dell\'utente da analizzare'),
      limit: z.number().default(3).describe('Numero massimo di risultati (default: 3)'),
      maxQueries: z.number().default(2).describe('Numero massimo di query (default: 2)'),
      includeContent: z.boolean().default(false).describe('Includere contenuto completo? (default: false)'),
    },
    async ({ task, limit, maxQueries, includeContent }) => {
      try {
        const client = new QdrantClient({ url: QDRANT_URL });

        // Estrai parole chiave dal task
        const keywords = extractKeywordsFromTask(task);
        console.error(`[GSD-Qdrant MCP] Estratte ${keywords.length} parole chiave:`, keywords);

        // Genera query di ricerca (max maxQueries)
        const queries = generateSearchQueries(keywords).slice(0, maxQueries);
        console.error(`[GSD-Qdrant MCP] Query generate:`, queries);

        // Esegui retrieval per ogni query
        const allResults = [];
        let vectorScoreSum = 0;
        let textScoreSum = 0;
        let vectorCount = 0;
        let textCount = 0;

        for (const query of queries) {
          // === VECTOR MATCHING ===
          const embedding = await generatePlaceholderEmbedding(query);

          const vectorHits = await client.search(COLLECTION_NAME, {
            vector: { name: VECTOR_NAME, vector: embedding },
            limit: parseInt(limit, 10),
            with_payload: true,
            with_vector: false
          });

          const vectorResults = vectorHits.map(hit => ({
            ...hit.payload,
            matchType: 'vector',
            originalScore: hit.score
          }));

          vectorScoreSum += vectorHits.reduce((sum, h) => sum + h.score, 0);
          vectorCount += vectorHits.length;
          allResults.push(...vectorResults);

          // === TEXT MATCHING (full-text search on source field) ===
          // Use Qdrant's full-text search via the 'text' vector name
          // This searches the indexed text fields in the collection
          let textHits = [];
          try {
            textHits = await client.search(COLLECTION_NAME, {
              vector: 'text', // Full-text search vector name
              limit: parseInt(limit, 10),
              with_payload: true,
              with_vector: false,
              query: query // Full-text search query
            });
          } catch (textErr) {
            // If text search fails (field not indexed), fall back to empty results
            console.error(`[GSD-Qdrant MCP] Text search failed (field may not be indexed): ${textErr.message}`);
            textHits = [];
          }

          const textResults = textHits.map(hit => ({
            ...hit.payload,
            matchType: 'text',
            originalScore: hit.score
          }));

          textScoreSum += textHits.reduce((sum, h) => sum + h.score, 0);
          textCount += textHits.length;
          allResults.push(...textResults);
        }

        // Log del confronto tra vector e text matching
        const totalScore = vectorScoreSum + textScoreSum;
        const vectorPercentage = totalScore > 0 ? (vectorScoreSum / totalScore * 100) : 0;
        const textPercentage = totalScore > 0 ? (textScoreSum / totalScore * 100) : 0;

        let dominantMatchType = 'balanced';
        if (vectorPercentage > textPercentage + 20) {
          dominantMatchType = 'vector';
        } else if (textPercentage > vectorPercentage + 20) {
          dominantMatchType = 'text';
        }

        console.error(`[GSD-Qdrant MCP] Matching Analysis:`);
        console.error(`  - Vector matches: ${vectorCount}, avg score: ${vectorCount > 0 ? (vectorScoreSum / vectorCount).toFixed(3) : 'N/A'}`);
        console.error(`  - Text matches: ${textCount}, avg score: ${textCount > 0 ? (textScoreSum / textCount).toFixed(3) : 'N/A'}`);
        console.error(`  - Dominant match type: ${dominantMatchType} (${vectorPercentage.toFixed(1)}% vector, ${textPercentage.toFixed(1)}% text)`);

        // Rimuovi duplicati basati su ID
        const uniqueResults = [...new Map(allResults.map(item => [item.id, item])).values()];

        // Ordina per score decrescente
        uniqueResults.sort((a, b) => (b.score || 0) - (a.score || 0));

        // Limita il numero totale di risultati restituiti
        const finalResults = uniqueResults.slice(0, limit);

        // Formatta risultati: includi contenuto completo solo per il top-1
        const formattedResults = finalResults.map((result, index) => {
          const formatted = {
            id: result.id,
            source: result.source,
            summary: result.summary,
            relevance_score: result.score,
            match_type: result.matchType,
            type: result.type,
            subtype: result.subtype,
          };

          // Include contenuto solo per il primo risultato
          if (index === 0 && includeContent) {
            formatted.content = result.content;
          }

          return formatted;
        });

        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              task,
              keywords,
              queries,
              results: formattedResults,
              totalFound: formattedResults.length,
              retrievalStrategy: 'auto-retrieve (limited context)',
              matchingAnalysis: {
                dominantType: dominantMatchType,
                vectorPercentage: vectorPercentage.toFixed(1),
                textPercentage: textPercentage.toFixed(1),
                vectorMatches: vectorCount,
                textMatches: textCount
              },
              note: 'Only metadata and summary included. Set includeContent=true to get full content.'
            }, null, 2)
          }]
        };
      } catch (err) {
        return {
          content: [{
            type: 'text',
            text: `Error in auto-retrieve: ${err.message}`
          }],
          isError: true
        };
      }
    }
  );

  // Strumento: list_projects
  // Restituisce la lista dei progetti indicizzati
  server.tool(
    'list_projects',
    'Restituisce la lista dei progetti unici indicizzati nella memoria GSD-Qdrant.',
    {},
    async () => {
      try {
        const client = new QdrantClient({ url: QDRANT_URL });

        // Scroll through all points to collect unique project_ids
        const allPoints = [];
        let offset = undefined;
        const batchSize = 1000;

        do {
          const result = await client.scroll(COLLECTION_NAME, {
            limit: batchSize,
            offset: offset,
            with_payload: ['project_id'],
            filter: {
              must: [{
                key: 'type',
                match: {
                  value: 'doc'
                }
              }]
            }
          });

          allPoints.push(...result);
          offset = result.length > 0 ? result[result.length - 1].payload.project_id : undefined;
        } while (allPoints.length % batchSize === 0);

        // Extract unique project_ids
        const projectIds = new Set(allPoints.map(p => p.payload.project_id).filter(Boolean));

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                projects: Array.from(projectIds).sort(),
                totalProjects: projectIds.size
              }, null, 2)
            }
          ]
        };
      } catch (err) {
        return {
          content: [
            {
              type: 'text',
              text: `Error listing projects: ${err.message}`
            }
          ],
          isError: true
        };
      }
    }
  );

  return server;
}

